// Step 1: Parse and verify Stripe webhook event
// In production, verify stripe-signature header against webhook secret.
// For now, parse the event and extract relevant data.

const event = $input.first().json.body || $input.first().json;

const eventType = event.type || 'unknown';
const eventData = event.data?.object || {};
const eventId = event.id || `evt_${Date.now()}`;
const today = new Date().toISOString().split('T')[0];

// Extract business_id from metadata, default to bayflow
const businessId = eventData.metadata?.business_id || eventData.subscription_details?.metadata?.business_id || 'bayflow';

// Extract common fields depending on event type
let amount = 0;
let currency = 'usd';
let customerId = eventData.customer || '';
let customerEmail = eventData.customer_email || eventData.customer_details?.email || '';
let subscriptionId = eventData.subscription || eventData.id || '';
let planInterval = eventData.plan?.interval || eventData.items?.data?.[0]?.plan?.interval || 'month';
let planAmount = eventData.plan?.amount || eventData.items?.data?.[0]?.plan?.amount || 0;
let channel = eventData.metadata?.channel || 'direct';

// For invoice events, amount is in cents
if (eventType.startsWith('invoice.')) {
  amount = (eventData.amount_paid || eventData.amount_due || 0) / 100;
  currency = eventData.currency || 'usd';
  customerEmail = eventData.customer_email || customerEmail;
}

// For checkout sessions
if (eventType === 'checkout.session.completed') {
  amount = (eventData.amount_total || 0) / 100;
  currency = eventData.currency || 'usd';
  customerEmail = eventData.customer_details?.email || customerEmail;
}

// For subscriptions, calculate MRR contribution
let subscriptionMrr = 0;
if (eventData.items?.data) {
  for (const item of eventData.items.data) {
    const unitAmount = (item.plan?.amount || item.price?.unit_amount || 0) / 100;
    const quantity = item.quantity || 1;
    const interval = item.plan?.interval || item.price?.recurring?.interval || 'month';
    if (interval === 'year') {
      subscriptionMrr += (unitAmount * quantity) / 12;
    } else {
      subscriptionMrr += unitAmount * quantity;
    }
  }
} else if (planAmount > 0) {
  subscriptionMrr = planInterval === 'year' ? (planAmount / 100) / 12 : planAmount / 100;
}

return [{
  json: {
    eventId,
    eventType,
    businessId,
    today,
    amount,
    currency,
    customerId,
    customerEmail,
    subscriptionId,
    subscriptionMrr,
    channel,
    planInterval,
    rawEvent: event
  }
}];

// checkout.session.completed
// Increment signups and conversions in daily_metrics
const event = $('Parse Stripe Event').first().json;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 1,
    conversions: 1,
    revenue_direct: event.amount,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: event.subscriptionMrr,
    _amount: event.amount
  }
}];

// customer.subscription.created
const event = $('Parse Stripe Event').first().json;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 1,
    conversions: 1,
    revenue_direct: 0,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: event.subscriptionMrr,
    _amount: 0
  }
}];

// customer.subscription.updated (plan change)
const event = $('Parse Stripe Event').first().json;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 0,
    conversions: 0,
    revenue_direct: 0,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: event.subscriptionMrr,
    _amount: 0
  }
}];

// customer.subscription.deleted (churn)
const event = $('Parse Stripe Event').first().json;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 0,
    conversions: 0,
    churn_count: 1,
    churn_mrr: event.subscriptionMrr,
    revenue_direct: 0,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: event.subscriptionMrr,
    _amount: 0
  }
}];

// invoice.payment_succeeded
const event = $('Parse Stripe Event').first().json;

// Determine revenue channel from metadata
const channelKey = `revenue_${event.channel}`;
const revenueObj = {};
revenueObj[channelKey] = event.amount;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 0,
    conversions: 0,
    ...revenueObj,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: event.subscriptionMrr,
    _amount: event.amount
  }
}];

// invoice.payment_failed
const event = $('Parse Stripe Event').first().json;

return [{
  json: {
    business_id: null,
    date: event.today,
    signups: 0,
    conversions: 0,
    revenue_direct: 0,
    channel: event.channel,
    _eventType: event.eventType,
    _subscriptionMrr: 0,
    _amount: event.amount
  }
}];

// Merge business UUID into metrics and prepare UPSERT payload
const metrics = $input.first().json;
const businessLookup = $('Lookup Business UUID').first().json;

// businessLookup is an array from Supabase GET
const businesses = Array.isArray(businessLookup) ? businessLookup : [businessLookup];
const business = businesses[0] || {};
const businessUuid = business.id || null;
const currentMrr = business.current_mrr || 0;
const totalRevenue = business.total_revenue || 0;

const eventType = metrics._eventType;
const subscriptionMrr = metrics._subscriptionMrr || 0;
const amount = metrics._amount || 0;

// Calculate new MRR based on event type
let newMrr = currentMrr;
if (eventType === 'checkout.session.completed' || eventType === 'customer.subscription.created') {
  newMrr = currentMrr + subscriptionMrr;
} else if (eventType === 'customer.subscription.deleted') {
  newMrr = Math.max(0, currentMrr - subscriptionMrr);
} else if (eventType === 'customer.subscription.updated') {
  // For plan changes, keep current MRR as-is.
  // Accurate MRR requires summing all active subs or comparing previous_attributes.
  newMrr = currentMrr;
}

// Calculate new total revenue
let newTotalRevenue = totalRevenue;
if (eventType === 'invoice.payment_succeeded' || eventType === 'checkout.session.completed') {
  newTotalRevenue = totalRevenue + amount;
}

// Build the daily_metrics UPSERT body
// Remove internal fields prefixed with _
const upsertBody = {};
for (const [key, val] of Object.entries(metrics)) {
  if (!key.startsWith('_')) {
    upsertBody[key] = val;
  }
}
upsertBody.business_id = businessUuid;

return [{
  json: {
    upsertBody,
    businessUuid,
    newMrr,
    newTotalRevenue,
    eventType,
    amount
  }
}];

// Build a markdown log entry for the Stripe event
const event = $('Parse Stripe Event').first().json;
const prepData = $('Prepare UPSERT Data').first().json;
const now = new Date();
const timeStr = now.toISOString().split('T')[1].split('.')[0];

const labels = {
  'checkout.session.completed': 'NEW CUSTOMER',
  'customer.subscription.created': 'NEW SUBSCRIPTION',
  'customer.subscription.updated': 'PLAN CHANGE',
  'customer.subscription.deleted': 'CHURN',
  'invoice.payment_succeeded': 'PAYMENT RECEIVED',
  'invoice.payment_failed': 'PAYMENT FAILED'
};

const label = labels[event.eventType] || event.eventType;

let entry = `### [${timeStr}] ${label}\n`;
entry += `- **Event ID:** ${event.eventId}\n`;
entry += `- **Type:** ${event.eventType}\n`;
entry += `- **Customer:** ${event.customerEmail || event.customerId || 'unknown'}\n`;

if (event.amount > 0) {
  entry += `- **Amount:** $${event.amount.toFixed(2)} ${event.currency.toUpperCase()}\n`;
}

if (event.subscriptionMrr > 0) {
  entry += `- **Subscription MRR:** $${event.subscriptionMrr.toFixed(2)}/mo\n`;
}

entry += `- **Channel:** ${event.channel}\n`;

if (prepData.newMrr !== undefined) {
  entry += `- **Updated MRR:** $${prepData.newMrr.toFixed(2)}\n`;
}
if (prepData.newTotalRevenue !== undefined) {
  entry += `- **Updated Total Revenue:** $${prepData.newTotalRevenue.toFixed(2)}\n`;
}

entry += `\n---\n\n`;

const filePath = `memory-bank/businesses/bayflow/reports/stripe-events-${event.today}.md`;

return [{
  json: {
    logEntry: entry,
    filePath,
    today: event.today,
    eventType: event.eventType
  }
}];

// Append the new log entry to the existing file or create a new one
const logData = $('Build Log Entry').first().json;
const readResult = $input.first().json;

let existingContent = '';
let sha = null;
let fileExists = false;

if (readResult.content && !readResult.error) {
  if (readResult.encoding === 'base64') {
    existingContent = Buffer.from(readResult.content, 'base64').toString('utf-8');
  } else {
    existingContent = readResult.content;
  }
  sha = readResult.sha;
  fileExists = true;
}

let fullContent;
if (fileExists && existingContent.trim().length > 0) {
  fullContent = existingContent.trimEnd() + '\n\n' + logData.logEntry;
} else {
  fullContent = `# Stripe Events - ${logData.today}\n\nReal revenue data from Stripe webhooks. Used by CEO Agent for accurate financial reporting.\n\n---\n\n` + logData.logEntry;
}

return [{
  json: {
    fileContent: fullContent,
    sha,
    fileExists,
    filePath: logData.filePath
  }
}];
